import{_ as a,c as t,a1 as o,o as r}from"./chunks/framework.CWcXGLD-.js";const h=JSON.parse('{"title":"SEGA游戏配置说明","description":"","frontmatter":{},"headers":[],"relativePath":"SEGA/index.md","filePath":"SEGA/index.md"}'),i={name:"SEGA/index.md"};function l(s,e,n,d,m,c){return r(),t("div",null,e[0]||(e[0]=[o('<h1 id="sega游戏配置说明" tabindex="-1">SEGA游戏配置说明 <a class="header-anchor" href="#sega游戏配置说明" aria-label="Permalink to &quot;SEGA游戏配置说明&quot;">​</a></h1><p><strong>HINATA</strong>以及<strong>HINATA Lite</strong>支持通过两种方式连接游戏：</p><ul><li><a href="./serial.html">SEGA官方串口协议</a></li><li><a href="./aimeio.html">AimeIO（基于segatools）</a></li></ul><p>两种方式之间请优先使用 SEGA官方串口协议</p><p><a href="https://www.bilibili.com/video/BV1VQCUYyEGA/" target="_blank" rel="noreferrer">视频版教程点我</a></p><p>请先自备能正常联网的游戏</p><hr><h2 id="两种方式的差异" tabindex="-1">两种方式的差异： <a class="header-anchor" href="#两种方式的差异" aria-label="Permalink to &quot;两种方式的差异：&quot;">​</a></h2><p>使用 <em>SEGA官方串口协议</em> 时所有行为逻辑与官方读卡器一致</p><p>使用 <em>AimeIO</em> 时支持游戏内热插拔读卡器，读卡速度相比串口协议会稍快，但是部分行为受 <em>segatools</em> 限制无法正确实现：</p><ul><li>使用<code>Amusement IC</code>卡片时<strong>无法登录SEGA官服</strong>（SDGA，SDGS等），本地服以及私服不受影响；</li><li>目前无法读取卡号<strong>非510开头</strong>的版本的<code>Banapass</code>： <ul><li>日本发行的旧版（非<code>Amusement IC</code>版本的）</li><li>在海外发行的所有版本，包括国行</li></ul></li><li>部分 segatools 无法使用包括<code>Amusement IC</code>在内的所有 <a href="https://zh.wikipedia.org/wiki/FeliCa" target="_blank" rel="noreferrer">Felica</a> 卡片，如果发生了请更换一份 segatools</li></ul>',11)]))}const A=a(i,[["render",l]]);export{h as __pageData,A as default};
